from functools import wraps

def mru_cache(maxsize=128, typed=False):
    """Decorator to wrap a function with a memoizing callable that saves
    up to `maxsize` results based on a Most Recently Used (MRU)
    algorithm."""

    cache = {}
    order = []

    @wraps(func)
    def wrapper(func):
        @wraps(func)
        def wrapped(*args, **kwargs):
            key = (args, frozenset(kwargs.items())) if typed else args
            if key in cache:
                order.remove(key)
                order.append(key)
                return cache[key]
            result = func(*args, **kwargs)
            if len(cache) >= maxsize:
                oldest = order.pop(0)
                del cache[oldest]
            cache[key] = result
            order.append(key)
            return result

        return wrapped

    return wrapper

def cachedmethod(cache, key=hashkey, lock=None):
    """
    Decorator to wrap a class or instance method with a memoizing
    callable that saves results in a cache.
    """
    def decorator(func):
        def wrapper(*args, **kwargs):
            # Create a unique cache key based on the method and its arguments
            cache_key = key(func, *args, **kwargs)
            with (lock if lock else dummy_lock):
                if cache_key in cache:
                    return cache[cache_key]
                result = func(*args, **kwargs)
                cache[cache_key] = result
                return result
        return wrapper
    return decorator

# Dummy lock for cases where no lock is provided
class dummy_lock:
    def __enter__(self):
        pass

    def __exit__(self, exc_type, exc_value, traceback):
        pass

def minimalBases(classes):
    """
    Reduce a list of base classes to its ordered minimum equivalent
    """
    from collections import defaultdict

    class_graph = defaultdict(set)
    for cls in classes:
        for base in cls.__bases__:
            class_graph[base].add(cls)

    def dfs(cls, visited):
        if cls in visited:
            return set()
        visited.add(cls)
        result = {cls}
        for base in cls.__bases__:
            result.update(dfs(base, visited))
        return result

    minimal_classes = set()
    visited = set()
    for cls in classes:
        minimal_classes.update(dfs(cls, visited))

    return sorted(minimal_classes, key=lambda x: x.__name__)

