def difference(d1, d2, level=-1):
    import copy

    if level == 0:
        return {}

    result = {}
    for key in d1:
        if key not in d2:
            result[key] = copy.deepcopy(d1[key])
        else:
            if isinstance(d1[key], dict) and isinstance(d2[key], dict):
                if level != 1:
                    nested_diff = difference(d1[key], d2[key], level - 1)
                    if nested_diff:
                        result[key] = nested_diff
            elif d1[key] != d2[key]:
                result[key] = copy.deepcopy(d1[key])

    return result

import re

class ValidationError(Exception):
    def __init__(self, messages):
        self.messages = messages

def _validate_labels(labels):
    key_regex = r'^[a-zA-Z_][a-zA-Z0-9_]*$'
    value_regex = r'^[a-zA-Z0-9_ ]+$'
    errors = []

    for key, value in labels.items():
        if not isinstance(key, str) or not re.match(key_regex, key):
            errors.append({key: f"Label key '{key}' does not match the regex [...]"})

        if isinstance(value, list):
            for item in value:
                if not isinstance(item, str) or not re.match(value_regex, item):
                    errors.append({str(item): 'expected string or bytes-like object'})
        elif not isinstance(value, str) or not re.match(value_regex, value):
            errors.append({str(value): 'expected string or bytes-like object'})

    if errors:
        raise ValidationError(errors)

def generate_default_observer_schema(app):
    """
    Generate the default observer schema for each Kubernetes resource present in
    ``spec.manifest`` for which a custom observer schema hasn't been specified.

    Args:
        app (krake.data.kubernetes.Application): The application for which to generate a
            default observer schema
    """
    default_schema = {}
    for resource in app.spec.manifest:
        resource_type = resource.get('kind')
        if resource_type not in app.custom_observer_schemas:
            default_schema[resource_type] = {
                'apiVersion': resource.get('apiVersion'),
                'metadata': {
                    'name': resource.get('metadata', {}).get('name'),
                    'namespace': resource.get('metadata', {}).get('namespace')
                },
                'spec': resource.get('spec', {})
            }
    return default_schema

