def absorb(self, args):
    """
    Given an `args` sequence of expressions, return a new list of expression
    applying absorption and negative absorption.

    See https://en.wikipedia.org/wiki/Absorption_law

    Absorption::

        A & (A | B) = A, A | (A & B) = A

    Negative absorption::

        A & (~A | B) = A & B, A | (~A & B) = A | B
    """
    result = []
    for expr in args:
        if isinstance(expr, tuple) and len(expr) == 3:
            a, op, b = expr
            if op == '&':
                if (a == b) or (b == ('|', a)):
                    result.append(a)
                elif (a == ('~', b)) or (b == ('|', ('~', a))):
                    result.append(('&', a, b))
                else:
                    result.append(expr)
            elif op == '|':
                if (a == b) or (b == ('&', a)):
                    result.append(a)
                elif (a == ('~', b)) or (b == ('&', ('~', a))):
                    result.append(('|', a, b))
                else:
                    result.append(expr)
        else:
            result.append(expr)
    return result

def _fromutc(self, dt):
    """
    Given a timezone-aware datetime in a given timezone, calculates a
    timezone-aware datetime in a new timezone.

    Since this is the one time that we *know* we have an unambiguous
    datetime object, we take this opportunity to determine whether the
    datetime is ambiguous and in a "fold" state (e.g. if it's the first
    occurrence, chronologically, of the ambiguous datetime).

    :param dt:
        A timezone-aware :class:`datetime.datetime` object.
    """
    if dt.tzinfo is None:
        raise ValueError("dt must be a timezone-aware datetime")

    # Convert the datetime to UTC
    utc_dt = dt.astimezone(self.utc)

    # Check if the datetime is ambiguous
    if self.is_ambiguous(utc_dt):
        # Determine if it's in the first or second fold
        if self.fold == 0:
            return utc_dt.replace(fold=0)
        else:
            return utc_dt.replace(fold=1)

    return utc_dt

def tzname_in_python2(namefunc):
    """
    Change unicode output into bytestrings in Python 2

    tzname() API changed in Python 3. It used to return bytes, but was changed
    to unicode strings
    """
    def wrapper(*args, **kwargs):
        result = namefunc(*args, **kwargs)
        if isinstance(result, unicode):
            return result.encode('utf-8')
        return result
    return wrapper

