    :param extra_vars: List of extra-vars
    """
    if extra_vars is None:
        return vars_dict

    for var in extra_vars:
        if isinstance(var, dict):
            vars_dict.update(var)
        else:
            key, value = var.split('=', 1)
            vars_dict[key] = value

    return vars_dict

